-- Backfill detail_content for each course slug from previously hardcoded data.
-- Only fills courses whose detail_content is still empty.

UPDATE public.courses SET detail_content = '{"longDescription":"Questo corso è perfetto sia per i bambini appassionati di Minecraft che per quelli che stanno appena iniziando a esplorare questo mondo. Offre una nuova prospettiva sul gioco, collegandolo alla programmazione, alla meccanica, al design e al pensiero ingegneristico. Passo dopo passo, gli studenti acquisiranno familiarità con l''ambiente Minecraft Education, automatizzeranno una serie di processi utilizzando redstone, progetteranno fattorie avanzate e svilupperanno le proprie costruzioni e meccanismi. Attraverso la programmazione basata su blocchi in MakeCode, i bambini scriveranno semplici algoritmi, controlleranno i loro agenti e interagiranno con il mondo di gioco tramite il codice.","age":"8-9 anni","level":"Principiante","duration":"40 lezioni","tags":["Minecraft","MakeCode","Programmazione a blocchi","Automazione","Redstone"],"topics":["Sviluppare una comprensione degli algoritmi e dei principi essenziali della programmazione","Imparare a utilizzare MakeCode per creare fattorie automatizzate, trappole e meccanismi","Ampliare i propri orizzonti esplorando la logica dei giochi e le interazioni","Sviluppare capacità di lavoro di squadra attraverso la costruzione collaborativa","Padroneggiare le basi della programmazione basata su blocchi"],"projectExamples":[{"title":"Fattorie automatizzate"},{"title":"Mini-giochi personalizzati"},{"title":"Città intelligente con automazione"}],"modules":[{"title":"Modulo 1. Il nuovo coraggioso mondo della Pietra Verde","lessons":["1. Introduzione al mondo di Minecraft. Esplorazione di Minecraft Education e MakeCode","2. Esplorazione dei comandi di movimento e mini-missione con labirinto","3. Dalle azioni semplici agli algoritmi. Apprendimento del ciclo di ripetizione","4. Costruire in squadra. Pianificare e costruire un edificio semplice","5. Lavorare con redstone per creare porte automatizzate","6. Utilizzare redstone e osservatori per costruire una fattoria complessa","7. Studiare i meccanismi in squadra per lo sviluppo della città","8. Completare la costruzione della città con MakeCode"],"result":"Il bambino imparerà le basi dell''algoritmizzazione, della logica dei loop e del controllo degli agenti, realizzando le prime costruzioni automatizzate."},{"title":"Modulo 2. La Città della Luce – Costruire il Futuro insieme","lessons":["9. Comprensione delle coordinate per la costruzione ad alta precisione","10. Progettazione di costruzioni su larga scala con loop annidati","11. Un progetto Agent – costruzione di un ponte sul fiume","12. Clonare oggetti per costruzioni simmetriche","13. Progettare una casa intelligente con automazione","14. Pianificare la disposizione delle strade e dei quartieri","15. Un progetto collaborativo – sviluppare il centro della città","16. Completamento del progetto finale – il ''Quartiere intelligente''"],"result":"Il bambino imparerà a utilizzare le coordinate e la clonazione in MakeCode per creare oggetti impressionanti e su larga scala."},{"title":"Modulo 3. Oasi della Logica – Creare Puzzle e giochi Divertenti","lessons":["17. Introduzione agli eventi e alle condizioni","18. Variabili e contatori per tenere traccia dei punteggi","19. È ora di intrappolare i mob! Programmare trappole","20. Progettazione del gioco ''Trova il pulsante''","21. Sviluppo del gioco ''Fuggi dalla lava''","22. Aggiunta di una zona di teletrasporto","23. Test e bilanciamento del gioco","24. Completare il progetto finale: ''Il mio gioco''"],"result":"Il bambino acquisirà comprensione di logica, istruzioni condizionali, variabili ed eventi, creando un gioco personalizzato controllato dal codice."},{"title":"Modulo 4. Una Foresta Meccanica – Automazione dei Sistemi Viventi","lessons":["25. Introduzione all''automazione – come funzionano le fattorie automatiche","26. Programmare un agente giardiniere","27. Costruire catene logiche condizionali","28. Progettare un selezionatore di risorse","29. Sviluppare una mob farm","30. Costruire un sistema di stoccaggio automatizzato","31. Manutenzione e ottimizzazione delle fattorie","32. Completamento del progetto finale: la ''fattoria intelligente''"],"result":"Il bambino capirà come automatizzare i processi, sviluppare un pensiero sistematico e creare circuiti complessi."},{"title":"Modulo 5. La Fortezza del Creator – Dare Vita ai Sogni","lessons":["33. Generare idee e selezionare un progetto","34. Creare un piano di progetto e assegnare i ruoli","35. Scrivere le prime righe di codice per i meccanismi base","36. Perfezionare le creazioni aggiungendo logica e automazione","37. Lavorare con le funzioni riutilizzabili","38. Gestire gli eventi per rispondere alle azioni dei giocatori","39. Aggiungere gli ultimi ritocchi e decorazioni","40. Presentare e difendere il progetto davanti alla classe"],"result":"Il bambino svilupperà un progetto da zero, dall''idea al codice, affinando le capacità di presentazione e la risoluzione creativa dei problemi."}]}'::jsonb WHERE slug = 'minecraft-education' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);

UPDATE public.courses SET detail_content = '{"longDescription":"FunTech Creators è un corso online per bambini dai 5 ai 7 anni, incentrato sulle basi del design digitale e dell''alfabetizzazione informatica. In esso, i bambini imparano a utilizzare editor grafici, creare biglietti di auguri, poster e semplici presentazioni. Acquisiscono padronanza di Google Docs e importanti competenze informatiche. Il corso è condotto in un formato ludico e sviluppa il pensiero creativo e logico.","age":"5-7 anni","level":"Principiante","duration":"32 lezioni","tags":["Design digitale","Creatività","Google Docs","Canva","Animazione"],"topics":["Sviluppare il pensiero creativo e immaginativo degli studenti","Insegnare ad utilizzare gli strumenti di base del design digitale","Creare progetti interessanti in Canva","Imparare a lavorare con testo e immagini in Google Docs e Google Slides","Apprendere le basi dell''alfabetizzazione informatica e della sicurezza online"],"projectExamples":[{"title":"Biglietti di auguri digitali"},{"title":"Poster e presentazioni"},{"title":"Animazioni GIF e melodie"}],"modules":[{"title":"Modulo 1. Scoprire il Mondo Digitale","lessons":["1. L''avventura dei tasti: conoscere il mouse e la tastiera","2. I miei primi disegni: introduzione alla grafica computerizzata","3. Imparare l''animazione: creare GIF","4. Lo studio musicale: creare una melodia"],"result":"I bambini impareranno a conoscere il computer: useranno mouse e tastiera, creeranno i loro primi disegni digitali, animazioni GIF e melodie."},{"title":"Modulo 2. Un''Avventura a Colorville","lessons":["5. Alla ricerca di una stella perduta","6. Il festival delle forme magiche a Colorville","7. Salvare la Galleria delle Meraviglie a Colorville","8. Festeggiamenti a Colorville"],"result":"I bambini impareranno a utilizzare un editor grafico, a disegnare con linee e forme e a creare i loro primi disegni!"},{"title":"Modulo 3. Avventure nella valle dei dati","lessons":["9. Foto fantastiche nell''Art Studio!","10. La magia del testo e i nostri fumetti!","11. Masterclass di progettazione di poster","12. Una cartolina dalla Valle dei Dati"],"result":"I bambini acquisiranno familiarità con la struttura dei file, impareranno cos''è Internet e creeranno fumetti, poster e cartoline digitali."},{"title":"Modulo 4. Un''avventura nel mondo della conoscenza","lessons":["13. Il viaggio attraverso i mari di Internet","14. La magia delle parole in Google Documenti","15. Un artista del testo","16. I cacciatori di conoscenza"],"result":"I bambini impareranno a creare e modificare documenti in Google Docs, con conoscenze sulla sicurezza in Internet."},{"title":"Modulo 5. Laboratorio di immaginazione","lessons":["17. Stimola la tua creatività con i Droodles!","18. La febbre degli adesivi a Canva","19. La routine quotidiana in immagini","20. I capolavori dei giovani maestri di Canva"],"result":"I bambini svilupperanno il pensiero creativo creando adesivi e progettando le loro routine in Canva!"},{"title":"Modulo 6. Cartoon Studio","lessons":["21. I primi passi nel Mondo dell''Animazione","22. Disegni danzanti","23. Andiamo a una festa danzante!","24. Piccoli detective: risolvere enigmi"],"result":"I bambini impareranno a creare animazioni in Flipanim e a trasformarle in veri video!"},{"title":"Modulo 7. Cyber Creator","lessons":["25. Primi passi in Google Presentazioni","26. Continuiamo a scrivere la nostra storia in Google Presentazioni","27. Le diapositive prendono vita!","28. Gara a squadre: Salvare TechnoTown"],"result":"I bambini impareranno a creare presentazioni colorate in Google Slides e rafforzeranno le conoscenze con progetti di gruppo."},{"title":"Modulo 8. Attività creative e Modellazione 3D","lessons":["29. Il Potere della Creatività: creare storie e personaggi","30. Odissea nello spazio: avventura nell''universo","31. Dare vita a un giardino con la modellazione 3D","32. Scoprire tesori in 3D"],"result":"I bambini impareranno a creare storie e a presentarle, con un''introduzione alla modellazione 3D!"}]}'::jsonb WHERE slug = 'abc-creativita-digitale' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);
